+    rosidl_runtime_c__type_description__TypeDescription * utils_desc = NULL;
+    EXPECT_EQ(
+      rosidl_runtime_c_type_description_utils_create_type_description(
+        test_name.c_str(),
+        test_name.size(), &utils_desc),
+      RCUTILS_RET_OK);
+    ASSERT_TRUE(utils_desc);
