+  // insert v2 after the 1st position
+  ASSERT_NO_THROW(v1.insert(it + 1, v2.begin(), v2.end()));
+  // insert v2 after the 4th position
+  ASSERT_THROW(v1.insert(it + 4, v2.begin(), v2.end()), std::length_error);
